var r = msg.payload;
// r[0] = reg100, r[1] = reg101, ... r[27] = reg127
// All temps in °C direct value unless noted.
// Negative temps: standard signed 16-bit two's complement
function s16(v) { return v > 32767 ? v - 65536 : v; }

// Operating mode decode
var modeMap = {0: 'Uit', 2: 'Koelen', 3: 'Verwarmen'};

var data = {
    timestamp:        new Date().toISOString(),
    comp_hz:          r[0],              // Reg 100: Compressor freq Hz
    bedrijfsmodus:    modeMap[r[1]] || 'Onbekend(' + r[1] + ')',  // Reg 101
    fan_rpm:          r[2],              // Reg 102: Fan speed r/min
    exv1_opening:     r[3],              // Reg 103: Expansion valve openness P
    Tw_in:            s16(r[4]),         // Reg 104: Plate HX water INLET (return) °C
    Tw_out:           s16(r[5]),         // Reg 105: Plate HX water OUTLET (flow) °C
    T3_condenser:     s16(r[6]),         // Reg 106: Condenser temp °C
    T4_buiten:        s16(r[7]),         // Reg 107: Outdoor ambient temp °C
    Tp_discharge:     s16(r[8]),         // Reg 108: Compressor discharge temp °C
    Th_suction:       s16(r[9]),         // Reg 109: Compressor suction temp °C
    T1_uitvoer:       s16(r[10]),        // Reg 110: Total outlet water temp °C
    Tw2_zone2:        s16(r[11]),        // Reg 111: Zone 2 water temp °C (25=unavailable)
    T2_ref_liquid:    s16(r[12]),        // Reg 112: Refrigerant liquid side temp °C
    T2B_ref_gas:      s16(r[13]),        // Reg 113: Refrigerant gas side temp °C
    Ta_kamer:         s16(r[14]),        // Reg 114: Room temp °C (25=unavailable)
    T5_tapwater:      s16(r[15]),        // Reg 115: DHW tank temp °C
    P1_hogedruk_kPa:  r[16],             // Reg 116: High pressure kPa
    P2_lagedruk_kPa:  r[17],             // Reg 117: Low pressure kPa
    odu_stroom_A:     r[18],             // Reg 118: ODU current A
    odu_spanning_V:   r[19],             // Reg 119: ODU voltage V
    Tbt1_buffer_top:  s16(r[20]),        // Reg 120: Buffer tank TOP temp °C
    Tbt2_buffer_bot:  s16(r[21]),        // Reg 121: Buffer tank BOTTOM temp °C
    comp_uren:        r[22],             // Reg 122: Compressor operating time hrs
    unit_vermogen_kW: r[23],             // Reg 123: Unit capacity kW
    foutcode:         r[24]              // Reg 124: Current error (0=OK)
};

// Persist for cross-node access
flow.set('sensor_data', data);

// Active fault warning
if (data.foutcode !== 0) {
    node.warn('ACTIEVE FOUT: code ' + data.foutcode +
        ' | Aanvoer: ' + data.Tw_out + 'C' +
        ' | Buiten: ' + data.T4_buiten + 'C');
}

// Sanity check: Tw2=25 means Zone 2 sensor unavailable (per Midea note)
if (data.Tw2_zone2 === 25) { data.Tw2_zone2 = null; }
// Ta=25 means room sensor unavailable
if (data.Ta_kamer === 25) { data.Ta_kamer = null; }

msg.payload = data;
return msg;

var r = msg.payload;

// Register 0 is a BIT field - decode each relevant bit
var reg0 = r[0];
var modeMap = {1: 'Auto', 2: 'Koelen', 3: 'Verwarmen'};

var data = {
    timestamp:        new Date().toISOString(),
    reg0_raw:         reg0,
    zone1_aan:        (reg0 & 0x0002) ? 'AAN' : 'UIT',  // BIT1: Zone1 water flow ctrl
    dhw_aan:          (reg0 & 0x0004) ? 'AAN' : 'UIT',  // BIT2: DHW
    zone2_aan:        (reg0 & 0x0008) ? 'AAN' : 'UIT',  // BIT3: Zone2 water flow ctrl
    eco_modus:        (reg0 & 0x0020) ? 'Actief' : 'Uit', // BIT5
    stille_modus:     (reg0 & 0x0100) ? 'Actief' : 'Uit', // BIT8
    modus:            modeMap[r[1]] || 'Onbekend(' + r[1] + ')',  // Reg 1
    setpoint_T1:      r[2],               // Reg 2: Zone 1 water temp setpoint °C
    setpoint_T1z2:    r[3],               // Reg 3: Zone 2 water temp setpoint °C
    setpoint_Tas:     r[4],               // Reg 4: Air temp setpoint °C
    setpoint_T5:      r[5],               // Reg 5: DHW setpoint °C
    func_setting:     r[6],               // Reg 6: Function setting (BIT field)
    curve_sel:        r[7]                // Reg 7: Temperature curve selection
};

flow.set('control_data', data);
msg.payload = data;
return msg;

var r = msg.payload;
// r[0]=reg148, r[1]=reg149, ... r[7]=reg155
// For R290 units: actual value = register value / 100

var data = {
    timestamp:             new Date().toISOString(),
    verwarm_vermogen_kW:   r[0] / 100,   // Reg 148: Real-time heating capacity kW
    hernieuw_vermogen_kW:  r[1] / 100,   // Reg 149: Real-time renewable heating kW
    elek_verbruik_kW:      r[2] / 100,   // Reg 150: Real-time heating power consumption kW
    COP_actueel:           r[3] / 100,   // Reg 151: Real-time heating COP
    koel_vermogen_kW:      r[4] / 100,   // Reg 152: Real-time cooling capacity kW
    koel_hernieuw_kW:      r[5] / 100,   // Reg 153: Real-time renewable cooling kW
    koel_verbruik_kW:      r[6] / 100,   // Reg 154: Real-time cooling power consumption kW
    EER_actueel:           r[7] / 100    // Reg 155: Real-time cooling EER
};

// Alert on unexpectedly low COP
if (data.COP_actueel > 0 && data.COP_actueel < 1.5) {
    node.warn('LAGE COP: ' + data.COP_actueel +
        ' | Vermogen: ' + data.verwarm_vermogen_kW + 'kW' +
        ' | Verbruik: ' + data.elek_verbruik_kW + 'kW');
}

flow.set('energy_data', data);
msg.payload = data;
return msg;

var d = msg.payload;
var written = flow.get('sensor_hdr') || false;
var out = '';
if (!written) {
    out = 'timestamp,comp_hz,bedrijfsmodus,fan_rpm,Tw_in,Tw_out,T3_condenser,T4_buiten,' +
          'Tp_discharge,Th_suction,T1_uitvoer,T5_tapwater,P1_hogedruk_kPa,P2_lagedruk_kPa,' +
          'odu_stroom_A,odu_spanning_V,Tbt1_buffer_top,Tbt2_buffer_bot,comp_uren,foutcode\n';
    flow.set('sensor_hdr', true);
}
out += [
    d.timestamp, d.comp_hz, d.bedrijfsmodus, d.fan_rpm,
    d.Tw_in, d.Tw_out, d.T3_condenser, d.T4_buiten,
    d.Tp_discharge, d.Th_suction, d.T1_uitvoer, d.T5_tapwater,
    d.P1_hogedruk_kPa, d.P2_lagedruk_kPa,
    d.odu_stroom_A, d.odu_spanning_V,
    d.Tbt1_buffer_top, d.Tbt2_buffer_bot,
    d.comp_uren, d.foutcode
].join(',') + '\n';
msg.payload = out;
msg.filename = '/home/student/modbus/amh6dc_sensors.csv';
return msg;

var d = msg.payload;
var written = flow.get('ctrl_hdr') || false;
var out = '';
if (!written) {
    out = 'timestamp,zone1_aan,dhw_aan,zone2_aan,eco_modus,stille_modus,modus,setpoint_T1,setpoint_T5,reg0_raw\n';
    flow.set('ctrl_hdr', true);
}
out += [
    d.timestamp, d.zone1_aan, d.dhw_aan, d.zone2_aan,
    d.eco_modus, d.stille_modus, d.modus,
    d.setpoint_T1, d.setpoint_T5, d.reg0_raw
].join(',') + '\n';
msg.payload = out;
msg.filename = '/home/student/modbus/amh6dc_controls.csv';
return msg;

var d = msg.payload;
var written = flow.get('energy_hdr') || false;
var out = '';
if (!written) {
    out = 'timestamp,verwarm_vermogen_kW,hernieuw_vermogen_kW,elek_verbruik_kW,COP_actueel,koel_vermogen_kW,EER_actueel\n';
    flow.set('energy_hdr', true);
}
out += [
    d.timestamp,
    d.verwarm_vermogen_kW,
    d.hernieuw_vermogen_kW,
    d.elek_verbruik_kW,
    d.COP_actueel,
    d.koel_vermogen_kW,
    d.EER_actueel
].join(',') + '\n';
msg.payload = out;
msg.filename = '/home/student/modbus/amh6dc_energy.csv';
return msg;

// Register 2 = T1s setpoint Zone 1
// Midea 120L: direct degrees C, no x10 scaling for this register
var val = Number(msg.payload);

if (isNaN(val) || val < 20 || val > 75) {
    node.error('Setpoint buiten bereik: ' + val + ' (verwacht 20-75 °C)', msg);
    return null;
}

node.log('Setpoint opdracht: ' + val + 'C → register 2');

msg.payload = {
    value:   [val],
    unitid:  1,
    fc:      6,      // FC6 = Write Single Register
    address: 2       // Reg 2 = T1s Zone 1 setpoint
};
return msg;

// Register 0 is a 16-bit BIT FIELD - never overwrite blindly!
// BIT1 = Zone 1 water flow temperature control on/off
//
// Strategy: READ current reg0, SET or CLEAR bit 1, WRITE back
// This preserves ECO mode (BIT5), Silent mode (BIT8), etc.
//
// msg.topic is preserved from inject via keepMsgProperties:true on the getter

var currentReg0 = msg.payload[0];  // Read result from Lees Reg 0
var topic = msg.topic || '';
var turnOn = (topic === 'HP_AAN');

var newReg0;
if (turnOn) {
    newReg0 = currentReg0 | 0x0002;   // SET BIT1
    node.log('Zone1 AAN: reg0 ' + currentReg0 + ' → ' + newReg0 + ' (BIT1 set)');
} else {
    newReg0 = currentReg0 & ~0x0002;  // CLEAR BIT1
    newReg0 = newReg0 & 0xFFFF;       // Ensure 16-bit unsigned
    node.log('Zone1 UIT: reg0 ' + currentReg0 + ' → ' + newReg0 + ' (BIT1 cleared)');
}

msg.payload = {
    value:   [newReg0],
    unitid:  1,
    fc:      6,       // FC6 = Write Single Register
    address: 0        // Reg 0 = Power on/off BIT field
};
msg.topic = turnOn ? 'HP_AAN' : 'HP_UIT';
return msg;

var r = msg.payload;
var reg0 = r[0];
var modeMap = {1: 'Auto', 2: 'Koelen', 3: 'Verwarmen'};

var result = {
    timestamp:      new Date().toISOString(),
    type:           'VERIFICATIE',
    reg0_raw:       reg0,
    zone1_aan:      (reg0 & 0x0002) ? 'AAN' : 'UIT',
    dhw_aan:        (reg0 & 0x0004) ? 'AAN' : 'UIT',
    eco_modus:      (reg0 & 0x0020) ? 'Actief' : 'Uit',
    stille_modus:   (reg0 & 0x0100) ? 'Actief' : 'Uit',
    modus:          modeMap[r[1]] || 'Onbekend',
    setpoint_T1:    r[2] + 'C'
};

msg.payload = result;
msg.topic = 'VERIFICATIE';
return msg;

var d = msg.payload;
var topic = msg.topic || 'onbekend';
var written = flow.get('cmd_hdr') || false;
var out = '';

if (!written) {
    out = 'timestamp,type,detail\n';
    flow.set('cmd_hdr', true);
}

var detail;
if (d && d.type === 'VERIFICATIE') {
    detail = 'zone1=' + d.zone1_aan +
             ' modus=' + d.modus +
             ' setpoint=' + d.setpoint_T1 +
             ' reg0=0x' + d.reg0_raw.toString(16).toUpperCase();
} else if (d && Array.isArray(d.value)) {
    detail = 'reg=' + d.address +
             ' waarde=' + d.value[0] +
             ' (0x' + d.value[0].toString(16).toUpperCase() + ')' +
             ' fc=' + d.fc;
} else {
    detail = JSON.stringify(d);
}

out += [new Date().toISOString(), topic, '"' + detail + '"'].join(',') + '\n';
msg.payload = out;
msg.filename = '/home/student/modbus/amh6dc_commands.csv';
return msg;

// Midea error code lookup table (from document error code table 1)
var errorCodes = {
    1:'E0 Water flow fault',
    3:'E2 Communication fault controller/hydraulic',
    4:'E3 Final outlet water temp sensor T1 fault',
    5:'E4 Water tank temp sensor T5 fault',
    6:'E5 Condenser outlet refrigerant temp sensor T3 fault',
    7:'E6 Ambient temp sensor T4 fault',
    8:'E7 Buffer tank top sensor Tbt1 fault',
    9:'E8 Water flow failure',
    10:'E9 Suction temp sensor Th fault',
    11:'EA Discharge temp sensor Tp fault',
    13:'Ec Buffer tank low sensor Tbt2 fault',
    14:'Ed Inlet water temp sensor Tw_in fault',
    20:'P0 Low pressure switch protection',
    21:'P1 High pressure switch protection',
    23:'P3 Compressor overcurrent',
    24:'P4 High discharge temp protection',
    25:'P5 dT water too big',
    26:'P6 Inverter module protection',
    31:'Pb Anti-freeze mode',
    38:'PP Tw_out-Tw_in unusual',
    39:'H0 Main board communication fault',
    41:'H2 Refrigerant liquid temp sensor T2 fault',
    45:'H6 DC fan motor fault',
    46:'H7 Voltage protection',
    57:'HP Low pressure protection'
};

var errMsg = '';
if (msg.error && msg.error.message) {
    errMsg = msg.error.message;
} else if (typeof msg.payload === 'string') {
    errMsg = msg.payload;
} else if (msg.payload && msg.payload.err) {
    errMsg = msg.payload.err;
} else {
    errMsg = JSON.stringify(msg.payload || 'onbekend');
}

// Enrich with Midea error description if active
var sensorData = flow.get('sensor_data');
if (sensorData && sensorData.foutcode > 0) {
    var code = sensorData.foutcode;
    var desc = errorCodes[code] || 'Foutcode ' + code;
    errMsg = errMsg + ' | HP fout: ' + desc;
}

var source = msg.topic || msg._alias || 'modbus';
var ts = new Date().toISOString();

node.error('Fout [' + source + ']: ' + errMsg);

var written = flow.get('err_hdr') || false;
var out = '';
if (!written) {
    out = 'timestamp,source,fout\n';
    flow.set('err_hdr', true);
}
out += [ts, source, '"' + errMsg.replace(/"/g, "'") + '"'].join(',') + '\n';

msg.payload = out;
msg.error_detail = errMsg;
msg.filename = '/home/student/modbus/amh6dc_errors.csv';
return msg;
